export type ItemType = 'sword' | 'amulet' | 'staff' | 'potion' | 'rune' | 'moonstone';

export interface Item {
  type: string;
  material?: string;
  enchantment?: number;
  cursed?: boolean;
}

export interface Customer {
  yearsWithMHPCO: number;
}

export interface QuoteStep {
  op: 'quote';
  items: Item[];
}

export interface Damage {
  itemType: string;
  amount: number;
}

export interface Incident {
  cause: string;
  damages: Damage[];
}

export interface ClaimStep {
  op: 'claim';
  policy: number;
  incident: Incident;
}

export type Step = QuoteStep | ClaimStep;

export interface Scenario {
  customer: Customer;
  steps: Step[];
}

export type QuoteResult = { premium: number };
export type ClaimResult = { payout: number; remainingCap: number };
export type StepResult = QuoteResult | ClaimResult;

export interface ScenarioOutput {
  results: StepResult[];
}

const MAIN_ITEMS: Record<string, { value: number; premium: number }> = {
  sword: { value: 1000, premium: 100 },
  amulet: { value: 600, premium: 60 },
  staff: { value: 800, premium: 80 },
  potion: { value: 400, premium: 40 },
};

const COMPONENT_TYPES = new Set(['rune', 'moonstone']);
const COMPONENT_VALUE = 250;
const COMPONENT_PREMIUM = 25;
const COMPONENT_BLOCK_PREMIUM = 60;
const COMPONENT_BLOCK_SIZE = 3;

const DEDUCTIBLE = 100;
const PROCESSING_FEE = 5;

function isKnownType(t: string): boolean {
  return t in MAIN_ITEMS || COMPONENT_TYPES.has(t);
}

function itemInsuranceValue(item: Item): number {
  if (item.type in MAIN_ITEMS) return MAIN_ITEMS[item.type].value;
  if (COMPONENT_TYPES.has(item.type)) return COMPONENT_VALUE;
  throw new Error(`Unknown item type: ${item.type}`);
}

function itemBasePremium(item: Item): number {
  if (item.type in MAIN_ITEMS) return MAIN_ITEMS[item.type].premium;
  if (COMPONENT_TYPES.has(item.type)) return COMPONENT_PREMIUM;
  throw new Error(`Unknown item type: ${item.type}`);
}

function applyItemModifiers(item: Item, basePremium: number): number {
  let p = basePremium;
  if (item.cursed) p += basePremium * 0.5;
  if ((item.enchantment ?? 0) >= 5) p += basePremium * 0.3;
  return p;
}

function policyItemBasePremiums(items: Item[]): number[] {
  // For components, group by type and apply block discount per group of 3
  const componentCounts: Record<string, number> = {};
  const mainPremiums: number[] = [];
  for (const item of items) {
    if (!isKnownType(item.type)) {
      throw new Error(`Unknown item type: ${item.type}`);
    }
    if (COMPONENT_TYPES.has(item.type)) {
      componentCounts[item.type] = (componentCounts[item.type] ?? 0) + 1;
    } else {
      mainPremiums.push(itemBasePremium(item));
    }
  }
  // For each component group, compute total base premium
  const componentTotals: number[] = [];
  for (const t of Object.keys(componentCounts)) {
    const count = componentCounts[t];
    const blocks = Math.floor(count / COMPONENT_BLOCK_SIZE);
    const leftover = count % COMPONENT_BLOCK_SIZE;
    const total = blocks * COMPONENT_BLOCK_PREMIUM + leftover * COMPONENT_PREMIUM;
    componentTotals.push(total);
  }
  return [...mainPremiums, ...componentTotals];
}

// We need item-level modifier amounts per item; for components in blocks the
// per-item premium is effectively averaged. But modifier examples don't seem
// to combine cursed runes with block discounts. Treat each main item with its
// own modifiers; components don't have enchantment/cursed in examples.
// For correctness in the general case: apply cursed/enchant to the
// post-discount per-item portion of the component group's base premium.

function computeItemizedBasePremium(items: Item[]): {
  itemModifierTotal: number;
  policyBaseTotal: number;
  firstInsuranceTotal: number;
} {
  // Build a list of per-item "base premium" contributions, then apply
  // item-level modifiers per item.
  // For components grouped into blocks: distribute the block discount
  // proportionally per item (effective per-item base = group total / count).
  const componentGroups: Record<string, Item[]> = {};
  const mainItems: Item[] = [];
  for (const item of items) {
    if (COMPONENT_TYPES.has(item.type)) {
      (componentGroups[item.type] ??= []).push(item);
    } else {
      mainItems.push(item);
    }
  }

  let itemModifierTotal = 0;
  let policyBaseTotal = 0;

  for (const item of mainItems) {
    const base = itemBasePremium(item);
    policyBaseTotal += base;
    itemModifierTotal += applyItemModifiers(item, base) - base;
  }

  for (const t of Object.keys(componentGroups)) {
    const group = componentGroups[t];
    const count = group.length;
    const blocks = Math.floor(count / COMPONENT_BLOCK_SIZE);
    const leftover = count % COMPONENT_BLOCK_SIZE;
    const groupTotal = blocks * COMPONENT_BLOCK_PREMIUM + leftover * COMPONENT_PREMIUM;
    policyBaseTotal += groupTotal;
    const perItem = groupTotal / count;
    for (const item of group) {
      itemModifierTotal += applyItemModifiers(item, perItem) - perItem;
    }
  }

  const firstInsuranceTotal = items.length; // 10% per item on its base premium
  return { itemModifierTotal, policyBaseTotal, firstInsuranceTotal };
}

export interface PremiumContext {
  yearsWithMHPCO: number;
  isFollowUpContract: boolean; // any contract after the first
}

export function computePremium(items: Item[], ctx: PremiumContext): number {
  for (const item of items) {
    if (!isKnownType(item.type)) {
      throw new Error(`Unknown item type: ${item.type}`);
    }
  }

  if (items.length === 0) {
    return PROCESSING_FEE;
  }

  // Compute per-item base premiums and item-level surcharges
  // First, build effective per-item base
  const componentGroups: Record<string, Item[]> = {};
  const mainItems: Item[] = [];
  for (const item of items) {
    if (COMPONENT_TYPES.has(item.type)) {
      (componentGroups[item.type] ??= []).push(item);
    } else {
      mainItems.push(item);
    }
  }

  let policyBaseTotal = 0;
  let itemModifierTotal = 0;
  let firstInsuranceSurchargeTotal = 0;

  for (const item of mainItems) {
    const base = itemBasePremium(item);
    policyBaseTotal += base;
    itemModifierTotal += applyItemModifiers(item, base) - base;
    firstInsuranceSurchargeTotal += base * 0.1;
  }

  for (const t of Object.keys(componentGroups)) {
    const group = componentGroups[t];
    const count = group.length;
    const blocks = Math.floor(count / COMPONENT_BLOCK_SIZE);
    const leftover = count % COMPONENT_BLOCK_SIZE;
    const groupTotal = blocks * COMPONENT_BLOCK_PREMIUM + leftover * COMPONENT_PREMIUM;
    policyBaseTotal += groupTotal;
    const perItem = groupTotal / count;
    for (const item of group) {
      itemModifierTotal += applyItemModifiers(item, perItem) - perItem;
      firstInsuranceSurchargeTotal += perItem * 0.1;
    }
  }

  // Policy-wide modifiers apply to policyBaseTotal (sum of item base premiums)
  let loyaltyDiscount = 0;
  if (ctx.yearsWithMHPCO >= 2) {
    loyaltyDiscount = policyBaseTotal * 0.2;
  }
  let followUpDiscount = 0;
  if (ctx.isFollowUpContract) {
    followUpDiscount = policyBaseTotal * 0.15;
  }

  const totalBeforeFee =
    policyBaseTotal +
    itemModifierTotal +
    firstInsuranceSurchargeTotal -
    loyaltyDiscount -
    followUpDiscount;

  const total = totalBeforeFee + PROCESSING_FEE;
  // Round up in MHPCO's favor
  return Math.ceil(total);
}

export interface PolicyState {
  insuranceSum: number;
  cap: number;
  remainingCap: number;
  itemCounts: Record<string, number>;
  itemsByType: Record<string, Item[]>;
}

export function createPolicy(items: Item[]): PolicyState {
  for (const item of items) {
    if (!isKnownType(item.type)) {
      throw new Error(`Unknown item type: ${item.type}`);
    }
  }
  let insuranceSum = 0;
  const itemCounts: Record<string, number> = {};
  const itemsByType: Record<string, Item[]> = {};
  for (const item of items) {
    insuranceSum += itemInsuranceValue(item);
    itemCounts[item.type] = (itemCounts[item.type] ?? 0) + 1;
    (itemsByType[item.type] ??= []).push(item);
  }
  const cap = insuranceSum * 2;
  return { insuranceSum, cap, remainingCap: cap, itemCounts, itemsByType };
}

export function processClaim(policy: PolicyState, incident: Incident): ClaimResult {
  // Validate all damages
  const usage: Record<string, number> = {};
  for (const d of incident.damages) {
    if (!isKnownType(d.itemType)) {
      throw new Error(`Unknown damage item type: ${d.itemType}`);
    }
    if (d.amount < 0) {
      throw new Error(`Negative damage amount: ${d.amount}`);
    }
    usage[d.itemType] = (usage[d.itemType] ?? 0) + 1;
    if ((policy.itemCounts[d.itemType] ?? 0) < usage[d.itemType]) {
      throw new Error(
        `Damage entry references item not in policy: ${d.itemType}`
      );
    }
  }

  // For each damage, compute reimbursement
  // Need to associate each damage entry with a specific item instance to
  // determine enchantment/material. Use them in order.
  const perTypeIndex: Record<string, number> = {};
  let totalPayout = 0;
  for (const d of incident.damages) {
    const idx = perTypeIndex[d.itemType] ?? 0;
    perTypeIndex[d.itemType] = idx + 1;
    const item = policy.itemsByType[d.itemType][idx];

    let reimbursable = d.amount;
    const ench = item.enchantment ?? 0;
    const isDragon = item.material === 'dragon';
    if (ench >= 8) {
      reimbursable = d.amount * 0.5;
    } else if (isDragon) {
      reimbursable = d.amount;
    }
    let perDamagePayout = reimbursable - DEDUCTIBLE;
    if (perDamagePayout < 0) perDamagePayout = 0;
    totalPayout += perDamagePayout;
  }

  // Round down (in MHPCO favor)
  let payout = Math.floor(totalPayout);
  if (payout > policy.remainingCap) payout = policy.remainingCap;
  policy.remainingCap -= payout;
  return { payout, remainingCap: policy.remainingCap };
}

export function runScenario(scenario: Scenario): ScenarioOutput {
  const results: StepResult[] = [];
  const policies: Record<number, PolicyState> = {};
  let quoteCount = 0;
  for (let i = 0; i < scenario.steps.length; i++) {
    const step = scenario.steps[i];
    if (step.op === 'quote') {
      const isFollowUp = quoteCount > 0;
      const ctx: PremiumContext = {
        yearsWithMHPCO: scenario.customer.yearsWithMHPCO,
        isFollowUpContract: isFollowUp,
      };
      const premium = computePremium(step.items, ctx);
      policies[i] = createPolicy(step.items);
      results.push({ premium });
      quoteCount++;
    } else if (step.op === 'claim') {
      const policy = policies[step.policy];
      if (!policy) {
        throw new Error(`Claim references unknown policy index: ${step.policy}`);
      }
      const result = processClaim(policy, step.incident);
      results.push(result);
    } else {
      throw new Error(`Unknown step op`);
    }
  }
  return { results };
}

