describe('modifier thresholds', () => {
  it('customer with exactly 2 years → loyalty discount applies', () => {
    // sword: 100 base; loyalty -20% = -20; first ins +10; fee +5 = 95
    expect(
      computePremium([{ type: 'sword' }], {
        yearsWithMHPCO: 2,
        isFollowUpContract: false,
      })
    ).toBe(95);
  });
