1	export type ItemType = 'sword' | 'amulet' | 'staff' | 'potion' | 'rune' | 'moonstone';
2	
3	export interface Item {
4	  type: string;
5	  material?: string;
6	  enchantment?: number;
7	  cursed?: boolean;
8	}
9	
10	export interface Customer {
11	  yearsWithMHPCO: number;
12	}
13	
14	export interface QuoteStep {
15	  op: 'quote';
16	  items: Item[];
17	}
18	
19	export interface Damage {
20	  itemType: string;
21	  amount: number;
22	}
23	
24	export interface Incident {
25	  cause: string;
26	  damages: Damage[];
27	}
28	
29	export interface ClaimStep {
30	  op: 'claim';
31	  policy: number;
32	  incident: Incident;
33	}
34	
35	export type Step = QuoteStep | ClaimStep;
36	
37	export interface Scenario {
38	  customer: Customer;
39	  steps: Step[];
40	}
41	
42	export type QuoteResult = { premium: number };
43	export type ClaimResult = { payout: number; remainingCap: number };
44	export type StepResult = QuoteResult | ClaimResult;
45	
46	export interface ScenarioOutput {
47	  results: StepResult[];
48	}
49	
50	const MAIN_ITEMS: Record<string, { value: number; premium: number }> = {
51	  sword: { value: 1000, premium: 100 },
52	  amulet: { value: 600, premium: 60 },
53	  staff: { value: 800, premium: 80 },
54	  potion: { value: 400, premium: 40 },
55	};
56	
57	const COMPONENT_TYPES = new Set(['rune', 'moonstone']);
58	const COMPONENT_VALUE = 250;
59	const COMPONENT_PREMIUM = 25;
60	const COMPONENT_BLOCK_PREMIUM = 60;
61	const COMPONENT_BLOCK_SIZE = 3;
62	
63	const DEDUCTIBLE = 100;
64	const PROCESSING_FEE = 5;
65	
66	function isKnownType(t: string): boolean {
67	  return t in MAIN_ITEMS || COMPONENT_TYPES.has(t);
68	}
69	
70	function itemInsuranceValue(item: Item): number {
71	  if (item.type in MAIN_ITEMS) return MAIN_ITEMS[item.type].value;
72	  if (COMPONENT_TYPES.has(item.type)) return COMPONENT_VALUE;
73	  throw new Error(`Unknown item type: ${item.type}`);
74	}
75	
76	function itemBasePremium(item: Item): number {
77	  if (item.type in MAIN_ITEMS) return MAIN_ITEMS[item.type].premium;
78	  if (COMPONENT_TYPES.has(item.type)) return COMPONENT_PREMIUM;
79	  throw new Error(`Unknown item type: ${item.type}`);
80	}
81	
82	function applyItemModifiers(item: Item, basePremium: number): number {
83	  let p = basePremium;
84	  if (item.cursed) p += basePremium * 0.5;
85	  if ((item.enchantment ?? 0) >= 5) p += basePremium * 0.3;
86	  return p;
87	}
88	
89	function policyItemBasePremiums(items: Item[]): number[] {
90	  // For components, group by type and apply block discount per group of 3
91	  const componentCounts: Record<string, number> = {};
92	  const mainPremiums: number[] = [];
93	  for (const item of items) {
94	    if (!isKnownType(item.type)) {
95	      throw new Error(`Unknown item type: ${item.type}`);
96	    }
97	    if (COMPONENT_TYPES.has(item.type)) {
98	      componentCounts[item.type] = (componentCounts[item.type] ?? 0) + 1;
99	    } else {
100	      mainPremiums.push(itemBasePremium(item));
101	    }
102	  }
103	  // For each component group, compute total base premium
104	  const componentTotals: number[] = [];
105	  for (const t of Object.keys(componentCounts)) {
106	    const count = componentCounts[t];
107	    const blocks = Math.floor(count / COMPONENT_BLOCK_SIZE);
108	    const leftover = count % COMPONENT_BLOCK_SIZE;
109	    const total = blocks * COMPONENT_BLOCK_PREMIUM + leftover * COMPONENT_PREMIUM;
110	    componentTotals.push(total);
111	  }
112	  return [...mainPremiums, ...componentTotals];
113	}
114	
115	// We need item-level modifier amounts per item; for components in blocks the
116	// per-item premium is effectively averaged. But modifier examples don't seem
117	// to combine cursed runes with block discounts. Treat each main item with its
118	// own modifiers; components don't have enchantment/cursed in examples.
119	// For correctness in the general case: apply cursed/enchant to the
120	// post-discount per-item portion of the component group's base premium.
121	
122	function computeItemizedBasePremium(items: Item[]): {
123	  itemModifierTotal: number;
124	  policyBaseTotal: number;
125	  firstInsuranceTotal: number;
126	} {
127	  // Build a list of per-item "base premium" contributions, then apply
128	  // item-level modifiers per item.
129	  // For components grouped into blocks: distribute the block discount
130	  // proportionally per item (effective per-item base = group total / count).
131	  const componentGroups: Record<string, Item[]> = {};
132	  const mainItems: Item[] = [];
133	  for (const item of items) {
134	    if (COMPONENT_TYPES.has(item.type)) {
135	      (componentGroups[item.type] ??= []).push(item);
136	    } else {
137	      mainItems.push(item);
138	    }
139	  }
140	
141	  let itemModifierTotal = 0;
142	  let policyBaseTotal = 0;
143	
144	  for (const item of mainItems) {
145	    const base = itemBasePremium(item);
146	    policyBaseTotal += base;
147	    itemModifierTotal += applyItemModifiers(item, base) - base;
148	  }
149	
150	  for (const t of Object.keys(componentGroups)) {
151	    const group = componentGroups[t];
152	    const count = group.length;
153	    const groupTotal =
154	      count === COMPONENT_BLOCK_SIZE
155	        ? COMPONENT_BLOCK_PREMIUM
156	        : count * COMPONENT_PREMIUM;
157	    policyBaseTotal += groupTotal;
158	    const perItem = groupTotal / count;
159	    for (const item of group) {
160	      itemModifierTotal += applyItemModifiers(item, perItem) - perItem;
161	    }
162	  }
163	
164	  const firstInsuranceTotal = items.length; // 10% per item on its base premium
165	  return { itemModifierTotal, policyBaseTotal, firstInsuranceTotal };
166	}
167	
168	export interface PremiumContext {
169	  yearsWithMHPCO: number;
170	  isFollowUpContract: boolean; // any contract after the first
171	}
172	
173	export function computePremium(items: Item[], ctx: PremiumContext): number {
174	  for (const item of items) {
175	    if (!isKnownType(item.type)) {
176	      throw new Error(`Unknown item type: ${item.type}`);
177	    }
178	  }
179	
180	  if (items.length === 0) {
181	    return PROCESSING_FEE;
182	  }
183	
184	  // Compute per-item base premiums and item-level surcharges
185	  // First, build effective per-item base
186	  const componentGroups: Record<string, Item[]> = {};
187	  const mainItems: Item[] = [];
188	  for (const item of items) {
189	    if (COMPONENT_TYPES.has(item.type)) {
190	      (componentGroups[item.type] ??= []).push(item);
191	    } else {
192	      mainItems.push(item);
193	    }
194	  }
195	
196	  let policyBaseTotal = 0;
197	  let itemModifierTotal = 0;
198	  let firstInsuranceSurchargeTotal = 0;
199	
200	  for (const item of mainItems) {
201	    const base = itemBasePremium(item);
202	    policyBaseTotal += base;
203	    itemModifierTotal += applyItemModifiers(item, base) - base;
204	    firstInsuranceSurchargeTotal += base * 0.1;
205	  }
206	
207	  for (const t of Object.keys(componentGroups)) {
208	    const group = componentGroups[t];
209	    const count = group.length;
210	    const groupTotal =
211	      count === COMPONENT_BLOCK_SIZE
212	        ? COMPONENT_BLOCK_PREMIUM
213	        : count * COMPONENT_PREMIUM;
214	    policyBaseTotal += groupTotal;
215	    const perItem = groupTotal / count;
216	    for (const item of group) {
217	      itemModifierTotal += applyItemModifiers(item, perItem) - perItem;
218	      firstInsuranceSurchargeTotal += perItem * 0.1;
219	    }
220	  }
221	
222	  // Policy-wide modifiers apply to policyBaseTotal (sum of item base premiums)
223	  let loyaltyDiscount = 0;
224	  if (ctx.yearsWithMHPCO >= 2) {
225	    loyaltyDiscount = policyBaseTotal * 0.2;
226	  }
227	  let followUpDiscount = 0;
228	  if (ctx.isFollowUpContract) {
229	    followUpDiscount = policyBaseTotal * 0.15;
230	  }
231	
232	  const totalBeforeFee =
233	    policyBaseTotal +
234	    itemModifierTotal +
235	    firstInsuranceSurchargeTotal -
236	    loyaltyDiscount -
237	    followUpDiscount;
238	
239	  const total = totalBeforeFee + PROCESSING_FEE;
240	  // Round up in MHPCO's favor
241	  return Math.ceil(total);
242	}
243	
244	export interface PolicyState {
245	  insuranceSum: number;
246	  cap: number;
247	  remainingCap: number;
248	  itemCounts: Record<string, number>;
249	  itemsByType: Record<string, Item[]>;
250	}
251	
252	export function createPolicy(items: Item[]): PolicyState {
253	  for (const item of items) {
254	    if (!isKnownType(item.type)) {
255	      throw new Error(`Unknown item type: ${item.type}`);
256	    }
257	  }
258	  let insuranceSum = 0;
259	  const itemCounts: Record<string, number> = {};
260	  const itemsByType: Record<string, Item[]> = {};
261	  for (const item of items) {
262	    insuranceSum += itemInsuranceValue(item);
263	    itemCounts[item.type] = (itemCounts[item.type] ?? 0) + 1;
264	    (itemsByType[item.type] ??= []).push(item);
265	  }
266	  const cap = insuranceSum * 2;
267	  return { insuranceSum, cap, remainingCap: cap, itemCounts, itemsByType };
268	}
269	
270	export function processClaim(policy: PolicyState, incident: Incident): ClaimResult {
271	  // Validate all damages
272	  const usage: Record<string, number> = {};
273	  for (const d of incident.damages) {
274	    if (!isKnownType(d.itemType)) {
275	      throw new Error(`Unknown damage item type: ${d.itemType}`);
276	    }
277	    if (d.amount < 0) {
278	      throw new Error(`Negative damage amount: ${d.amount}`);
279	    }
280	    usage[d.itemType] = (usage[d.itemType] ?? 0) + 1;
281	    if ((policy.itemCounts[d.itemType] ?? 0) < usage[d.itemType]) {
282	      throw new Error(
283	        `Damage entry references item not in policy: ${d.itemType}`
284	      );
285	    }
286	  }
287	
288	  // For each damage, compute reimbursement
289	  // Need to associate each damage entry with a specific item instance to
290	  // determine enchantment/material. Use them in order.
291	  const perTypeIndex: Record<string, number> = {};
292	  let totalPayout = 0;
293	  for (const d of incident.damages) {
294	    const idx = perTypeIndex[d.itemType] ?? 0;
295	    perTypeIndex[d.itemType] = idx + 1;
296	    const item = policy.itemsByType[d.itemType][idx];
297	
298	    let reimbursable = d.amount;
299	    const ench = item.enchantment ?? 0;
300	    const isDragon = item.material === 'dragon';
301	    if (ench >= 8) {
302	      reimbursable = d.amount * 0.5;
303	    } else if (isDragon) {
304	      reimbursable = d.amount;
305	    }
306	    let perDamagePayout = reimbursable - DEDUCTIBLE;
307	    if (perDamagePayout < 0) perDamagePayout = 0;
308	    totalPayout += perDamagePayout;
309	  }
310	
311	  // Round down (in MHPCO favor)
312	  let payout = Math.floor(totalPayout);
313	  if (payout > policy.remainingCap) payout = policy.remainingCap;
314	  policy.remainingCap -= payout;
315	  return { payout, remainingCap: policy.remainingCap };
316	}
317	
318	export function runScenario(scenario: Scenario): ScenarioOutput {
319	  const results: StepResult[] = [];
320	  const policies: Record<number, PolicyState> = {};
321	  let quoteCount = 0;
322	  for (let i = 0; i < scenario.steps.length; i++) {
323	    const step = scenario.steps[i];
324	    if (step.op === 'quote') {
325	      const isFollowUp = quoteCount > 0;
326	      const ctx: PremiumContext = {
327	        yearsWithMHPCO: scenario.customer.yearsWithMHPCO,
328	        isFollowUpContract: isFollowUp,
329	      };
330	      const premium = computePremium(step.items, ctx);
331	      policies[i] = createPolicy(step.items);
332	      results.push({ premium });
333	      quoteCount++;
334	    } else if (step.op === 'claim') {
335	      const policy = policies[step.policy];
336	      if (!policy) {
337	        throw new Error(`Claim references unknown policy index: ${step.policy}`);
338	      }
339	      const result = processClaim(policy, step.incident);
